namespace sv_56203a8215de402cbdcfed83c7864094.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single circuit.
/// Because Blazor Server scopes DI to the circuit, each user gets their own instance.
/// Components across render-mode boundaries share state through this service
/// instead of CascadingValue (which cannot cross static → interactive boundaries).
/// </summary>
public sealed class WarehouseState
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId => _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }

    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("WH-001", "Warehouse A — East"),
        ("WH-002", "Warehouse B — West"),
        ("WH-003", "Warehouse C — Central"),
    ];
}

namespace sv_56203a8215de402cbdcfed83c7864094.Services;

/// <summary>
/// Scoped service that simulates checking low-stock inventory counts.
/// Exposes an event so that when any component fetches new data, all
/// subscribed components (siblings, unrelated) are notified to re-render.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public int LastKnownCount { get; private set; }

    /// <summary>
    /// Fired after new alert data is fetched. All subscribed components should re-render.
    /// </summary>
    public event Action? OnAlertUpdated;

    /// <summary>
    /// Simulates a database query for items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call; return random count 0-15.
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Called by the polling component to store the latest count and
    /// broadcast the update to every subscriber (sidebar badge, dashboard, etc.).
    /// </summary>
    public void PublishUpdate(int count)
    {
        LastKnownCount = count;
        OnAlertUpdated?.Invoke();
    }
}

@using sv_56203a8215de402cbdcfed83c7864094.Services
@implements IDisposable
@inject WarehouseState WarehouseState
@rendermode InteractiveServer

<div class="warehouse-selector">
    <label class="form-label text-white mb-1" for="warehouse-select">Current Warehouse</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_56203a8215de402cbdcfed83c7864094.Services
@implements IDisposable
@inject InventoryAlertService AlertService
@rendermode InteractiveServer

<span class="badge @BadgeClass">@AlertService.LastKnownCount</span>

@code {
    private string BadgeClass => AlertService.LastKnownCount switch
    {
        0 => "bg-success",
        <= 5 => "bg-warning text-dark",
        _ => "bg-danger"
    };

    protected override void OnInitialized()
    {
        AlertService.OnAlertUpdated += OnAlertUpdated;
    }

    private void OnAlertUpdated()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertUpdated -= OnAlertUpdated;
    }
}

@page "/dashboard"
@using sv_56203a8215de402cbdcfed83c7864094.Services
@using sv_56203a8215de402cbdcfed83c7864094.Components.Shared
@implements IDisposable
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@rendermode InteractiveServer

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            @GetWarehouseName()
        </h5>
        <p class="card-text">
            Low-stock alerts: <AlertBadge />
        </p>
        <p class="text-muted">
            <small>Polling every 10 seconds. Last check: @_lastPollTime?.ToString("T")</small>
        </p>
    </div>
</div>

<div class="row">
    <div class="col-md-4">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Active Orders</h5>
                <p class="card-text display-6">@_activeOrders</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Shipments</h5>
                <p class="card-text display-6">@_pendingShipments</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-secondary mb-3">
            <div class="card-body">
                <h5 class="card-title">Items in Stock</h5>
                <p class="card-text display-6">@_itemsInStock</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private DateTime? _lastPollTime;
    private int _activeOrders;
    private int _pendingShipments;
    private int _itemsInStock;
    private readonly Random _random = new();

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertUpdated += OnAlertUpdated;
        RefreshSimulatedMetrics();
        await PollOnceAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await PollOnceAsync();
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task PollOnceAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastPollTime = DateTime.Now;
        // Broadcast to ALL subscribers (sidebar badge, this page, etc.)
        AlertService.PublishUpdate(count);
    }

    private void OnWarehouseChanged()
    {
        InvokeAsync(async () =>
        {
            RefreshSimulatedMetrics();
            await PollOnceAsync();
            StartPolling();
            StateHasChanged();
        });
    }

    private void OnAlertUpdated()
    {
        InvokeAsync(StateHasChanged);
    }

    private void RefreshSimulatedMetrics()
    {
        _activeOrders = _random.Next(5, 80);
        _pendingShipments = _random.Next(0, 30);
        _itemsInStock = _random.Next(200, 5000);
    }

    private string GetWarehouseName()
    {
        return WarehouseState.AvailableWarehouses
            .FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId).Name
            ?? WarehouseState.CurrentWarehouseId;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertUpdated -= OnAlertUpdated;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

